function solve(m, n, waitCost) {
    const INF = Infinity;
    const dist = new Array(m).fill().map(() => new Array(n).fill().map(() => [INF, INF]));
    dist[0][0][1] = 1;

    let pq = [[1, 0, 0, 1]];
    const directions = [[1, 0], [0, 1]];

    function push(cost, i, j, parity) {
        pq.push([cost, i, j, parity]);
        let idx = pq.length - 1;
        while (idx > 0) {
            let parent = Math.floor((idx - 1) / 2);
            if (pq[idx][0] < pq[parent][0]) {
                [pq[idx], pq[parent]] = [pq[parent], pq[idx]];
                idx = parent;
            } else {
                break;
            }
        }
    }

    function pop() {
        if (pq.length === 0) return null;
        const min = pq[0];
        pq.shift();
        let idx = 0;
        while (true) {
            let left = 2 * idx + 1;
            let right = 2 * idx + 2;
            let smallest = idx;
            if (left < pq.length && pq[left][0] < pq[smallest][0]) {
                smallest = left;
            }
            if (right < pq.length && pq[right][0] < pq[smallest][0]) {
                smallest = right;
            }
            if (smallest === idx) break;
            [pq[idx], pq[smallest]] = [pq[smallest], pq[idx]];
            idx = smallest;
        }
        return min;
    }

    while (pq.length > 0) {
        const [cost, i, j, parity] = pop();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][parity]) {
            continue;
        }

        if (parity === 1) {
            for (const [di, dj] of directions) {
                const ni = i + di;
                const nj = j + dj;
                if (ni < m && nj < n) {
                    const newCost = cost + (ni + 1) * (nj + 1);
                    if (newCost < dist[ni][nj][0]) {
                        dist[ni][nj][0] = newCost;
                        push(newCost, ni, nj, 0);
                    }
                }
            }
        } else {
            const newCost = cost + waitCost[i][j];
            if (newCost < dist[i][j][1]) {
                dist[i][j][1] = newCost;
                push(newCost, i, j, 1);
            }
        }
    }

    return -1;
